#include<bits/stdc++.h>
#define N (long long)(1e5+10)
using namespace std;
const long long inf=1e16;
long long n,q,d[N],c[N];
stack<long long>s;
long long l[N],head[N],size=0;
struct node {
	long long next,to;
}edge[N];
inline void push(long long x,long long y) {edge[++size].to=y,edge[size].next=head[x],head[x]=size;}
long long f[N][21],g[N][21],dep[N];
inline void dfs(long long u,long long fa) {
	dep[u]=dep[fa]+1;
	f[u][0]=fa;g[u][0]=c[fa];
	for(long long i=1;(1<<i)<=dep[u];i++) f[u][i]=f[f[u][i-1]][i-1],g[u][i]=g[f[u][i-1]][i-1]+g[u][i-1];
	for(long long i=head[u];i;i=edge[i].next) {
		long long v=edge[i].to;
		dfs(v,u);
	}
}
int main(void) {
	cin>>n>>q;
	for(long long i=1;i<=n;i++) cin>>d[i]>>c[i];
	d[n+1]=inf; c[n+1]=inf;
	s.push(1);
	for(long long i=2;i<=n+1;i++) {
		while (!s.empty()&&d[i]>d[s.top()]) {l[s.top()]=i; s.pop();}
		s.push(i);
	}for(long long i=1;i<=n;i++) push(l[i],i);
	dfs(n+1,0);
	for(long long i=1;i<=q;i++){
		long long r,v;cin>>r>>v;
		if(c[r]>=v){cout<<r<<endl;continue;}
		v-=c[r];long long x=r;long long ans=0;
		for(long long i=20;i>=0;i--){if(g[x][i]<=v&&(1<<i)<=dep[x])v-=g[x][i],x=f[x][i];if(v==0)ans=x;}
		if(ans==0)ans=f[x][0];
		if(ans==n+1)cout<<0<<endl;else cout<<ans<<endl;
	}
	return 0;
}
